let inputData = [];
let inputChatData = '';

try {
  inputData = $('Workflow Initiated').all();
  const json = inputData[0].json;
  inputData = json?.formatted_theme ?? null;
} catch(e) {}

if (!inputData) {
  try {
    inputChatData = $('When chat message received').first().json.chatInput;
    inputData = JSON.parse(inputChatData);
    inputData = inputData[0].Formatted_theme;
  } catch(e) {}
}

return [
  {
    json: {
      inputData
    }
  }
];

// --- Get Markdown content safely ---
const markdownNode = $('Code').first();
const Input = markdownNode?.json?.inputData || '';

// --- Gather all feedback entries ---
const feedbackArray = $input.all()
  .map(item => item.json.feedback_text)
  .filter(f => f && f.trim() !== '');

// --- Combine feedback into a bullet-style list ---
const aggregatedFeedback = feedbackArray.length
  ? feedbackArray.map(f => `• ${f}`).join('\n')
  : '';

// --- Return both for use in LLM prompt ---
return [
  {
    json: {
      aggregatedFeedback,
      Input,
    },
  },
];

let original_text = null;
let re_generated_text = null;
let switch_value = null;
let hasIntroduction = null;
let feedback = null;

try {
  original_text = $('Generate Markdown using LLM').first().json.output.data;
} catch (e) {
  // Node possibly unexecuted; leave as null
}

try {
  re_generated_text = $('Re-Generate Data using LLM').first().json.output.data;
  hasIntroduction = re_generated_text.includes('# *INTRODUCTION*');
} catch (e) {
  // Node possibly unexecuted; leave as null
}

try {
  switch_value = $('Switch').first().json.data["Ready to proceed to next step ?"];
} catch (e) {
  // Node possibly unexecuted; leave as null
}

let text;

if (switch_value && String(switch_value).trim().toLowerCase() !== 'yes' && String(switch_value).trim().toLowerCase() !== 'Provide Feedback' ) {
  text = original_text;
} else if (!hasIntroduction) {
  text = original_text;
} else {
  text = re_generated_text ?? original_text;
}

if (re_generated_text && !hasIntroduction) {
  feedback = re_generated_text;
} else {
  feedback = text
}

return [{ json: { text, feedback } }];

