// --------------------
// INPUT
// --------------------
const raw = $input.first().json.output.data;

// --------------------
// HELPERS
// --------------------
const countChars = s => (s || "").length;
const errors = [];

function rangeError(section, field, current, min, max) {
  if (current < min) {
    errors.push(
      `${section} – ${field} – current=${current} – target=${min}–${max} – delta=${current - min}`
    );
  } else if (current > max) {
    errors.push(
      `${section} – ${field} – current=${current} – target=${min}–${max} – delta=+${current - max}`
    );
  }
}

// --------------------
// SECTION EXTRACTOR
// --------------------
function extractSection(title) {
  const pattern = new RegExp(
    `#\\s*\\*?${title}\\*?\\s*\\n([\\s\\S]*?)(?=\\n#\\s*\\*?|$)`,
    "i"
  );
  const match = raw.match(pattern);
  return match ? match[1].trim() : "";
}

// =====================================================
// QUICK HIGHLIGHTS
// =====================================================
const quick = extractSection("QUICK HIGHLIGHTS");
const quickBullets = quick
  .split("\n")
  .filter(l => l.startsWith("• ") || l.startsWith("- "))
  .map(l => l.replace(/^• |^- /, "").trim());

if (quickBullets.length === 3) {
  quickBullets.forEach((b, i) =>
    rangeError(
      "Quick Highlights",
      `Bullet ${i + 1}`,
      countChars(b),
      150,
      190
    )
  );
}

// =====================================================
// FEATURED ARTICLE
// =====================================================
const featured = extractSection("FEATURED ARTICLE");
const featuredBody = featured.replace(/^##\s+.*$/m, "").trim();

const ctaMatch = featuredBody.match(/^.*→.*$/m);
const cta = ctaMatch ? ctaMatch[0] : "";

const featuredNoCTA = cta
  ? featuredBody.replace(cta, "").trim()
  : featuredBody;

const paras = featuredNoCTA
  .split(/\n\s*\n/)
  .map(p => p.trim())
  .filter(Boolean);

const p1 = paras[0] || "";
const p2 = paras[1] || "";
const insight = paras.find(p => p.startsWith("**")) || "";

rangeError("Featured Article", "Paragraph 1", countChars(p1), 300, 400);
rangeError("Featured Article", "Paragraph 2", countChars(p2), 300, 400);
rangeError(
  "Featured Article",
  "Key Insight paragraph",
  countChars(insight),
  300,
  370
);

// =====================================================
// MAIN ARTICLES
// =====================================================
function parseMain(title, index) {
  const sec = extractSection(title)
    .replace(/^##\s+.*$/m, "")
    .replace(/^\[.*→\]\(.*?\)$/gm, "")
    .trim();

  const paras = sec
    .split(/\n\s*\n/)
    .map(p => p.trim())
    .filter(Boolean);

  const callout = paras.find(p => /^(\*\*|\*)[^*]+:\1/.test(p)) || "";
  const content = paras.find(p => p !== callout) || "";

  rangeError(
    `Main Article ${index}`,
    "Callout Paragraph",
    countChars(callout),
    180,
    250
  );

  if (countChars(content) > 750) {
    errors.push(
      `Main Article ${index} – Content Paragraph – current=${countChars(
        content
      )} – target=max 750 – delta=+${countChars(content) - 750}`
    );
  }
}

parseMain("MAIN ARTICLE 1", 1);
parseMain("MAIN ARTICLE 2", 2);

// =====================================================
// INDUSTRY DEVELOPMENTS
// =====================================================
const industry = extractSection("INDUSTRY DEVELOPMENTS")
  .split("\n")
  .map(l => l.trim())
  .filter(l => l.startsWith("["))
  .slice(0, 2);

industry.forEach((item, i) =>
  rangeError(
    "Industry Developments",
    `Industry ${i + 1}`,
    countChars(item),
    200,
    280
  )
);

// =====================================================
// FOOTER
// =====================================================
const footerLines = extractSection("FOOTER")
  .split("\n")
  .map(l => l.trim())
  .filter(Boolean);

rangeError("Footer", "Paragraph 2", countChars(footerLines[1] || ""), 200, 550);
rangeError("Footer", "Paragraph 3", countChars(footerLines[2] || ""), 200, 550);

// =====================================================
// OUTPUT
// =====================================================
return {
  charErrors: errors
};

// Safely read the nested value from incoming item
const raw = $input.first().json.output.output;
const markdown = $('Generate Markdown using LLM').first().json.output.data;

// Track iteration count (persisted through loop)
const staticData = $getWorkflowStaticData('node');
const execId = $execution.id;
// Initialize run counter if not present
if (!staticData[execId]) {
  staticData[execId] = 0;
}
// Increment the run count
staticData[execId] += 1;

// Parse safely
let parsed;

if (raw && typeof raw === "object") {
  parsed = raw; // already parsed
} else {
  try {
    parsed = JSON.parse(raw); // only use this if raw is a string
  } catch (e) {
    parsed = {
      error: "Invalid JSON returned by validator",
      raw
    };
  }
}

// HARD LOOP BREAKER — force accept after N attempts
const MAX_ATTEMPTS = 3;

if (staticData[execId] >= MAX_ATTEMPTS) {
  parsed.isValid = true;
}

// Return clean JSON
return [
  {
    json: {
      parsed,
      markdown,
      runCount: staticData[execId]
    }
  }
];

